mod pty;

#[cfg(debug_assertions)]
mod dev_bridge;

use pty::PtyManager;
use std::sync::Arc;

#[tauri::command]
fn greet(name: &str) -> String {
    format!("Hello, {}! You've been greeted from Rust!", name)
}

#[cfg_attr(mobile, tauri::mobile_entry_point)]
pub fn run() {
    let pty_manager = Arc::new(PtyManager::new());

    // Start dev bridge in debug mode
    #[cfg(debug_assertions)]
    {
        let pty_for_bridge = pty_manager.clone();
        std::thread::spawn(move || {
            let rt = tokio::runtime::Runtime::new().unwrap();
            rt.block_on(async {
                let (_token, handle) = dev_bridge::start_dev_bridge(pty_for_bridge, None).await;
                handle.await.unwrap();
            });
        });
    }

    tauri::Builder::default()
        .plugin(tauri_plugin_shell::init())
        .manage(pty_manager)
        .invoke_handler(tauri::generate_handler![
            greet,
            pty::pty_spawn,
            pty::pty_write,
            pty::pty_resize,
            pty::pty_kill,
            pty::pty_list,
            pty::pty_get,
        ])
        .run(tauri::generate_context!())
        .expect("error while running tauri application");
}

// Prevents additional console window on Windows in release, DO NOT REMOVE!!
#![cfg_attr(not(debug_assertions), windows_subsystem = "windows")]

fn main() {
    hq_lib::run()
}

//! Dev Bridge - Secure RPC bridge for browser-to-native communication
//!
//! This module provides a development-only WebSocket server that mirrors Tauri commands,
//! allowing Playwright and other browser-based tools to interact with native features.
//!
//! SECURITY:
//! - Only compiled in debug mode (#[cfg(debug_assertions)])
//! - localhost-only binding (127.0.0.1)
//! - Token-based authentication
//! - Command allowlist (no arbitrary execution)

#![cfg(debug_assertions)]

use crate::pty::{PtyManager, ProcessInfo};
use axum::{
    extract::{
        ws::{Message, WebSocket, WebSocketUpgrade},
        Query, State,
    },
    http::StatusCode,
    response::{IntoResponse, Response},
    routing::get,
    Router,
};
use futures_util::{SinkExt, StreamExt};
